#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();bool f=0;while(ch<'0'||ch>'9')f^=ch=='-',ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return f ? -res : res ;
}
using namespace std;typedef long long ll;
//#define int ll
const int dx[12]={1,1,0,-1,-1,-1,0,1,2,-2,0,0},dy[12]={0,1,1,1,0,-1,-1,-1,0,0,2,-2};
typedef pair<int,int> pii;map<pii,int>idx;
const int N=15;int X,Y,que[N],H,T;ll dis[N];
const ll INF=0x3f3f3f3f3f3f3f3fll;
inline ll work(ll x,ll y)
{
	if(!x&&!y)return 0;
	if(!x)
	{
		int p1=idx[{0,y<0?-1:1}],p2=idx[{0,y<0?-2:2}];y=abs(y);
		if(dis[p2]>=INF||((y&1)&&dis[p1]>=INF))return INF;return (y>>1)*dis[p2]+(y&1)*dis[p1];
	}
	if(!y)
	{
		int p1=idx[{x<0?-1:1,0}],p2=idx[{x<0?-2:2,0}];x=abs(x);
		if(dis[p2]>=INF||((x&1)&&dis[p1]>=INF))return INF;return (x>>1)*dis[p2]+(x&1)*dis[p1];
	}
	ll ans=min(INF,work(x,0)+work(0,y)),p=idx[{x<0?-1:1,y<0?-1:1}],k=min(x/dx[p],y/dy[p]);
	if(dis[p]<INF)
	{
//		printf("QAQ :: %d %d\n",p,k);
		ans=min(ans,k*dis[p]+work(x-k*dx[p],y-k*dy[p]));
		if(k>1)ans=min(ans,(k-1)*dis[p]+work(x-(k-1)*dx[p],y-(k-1)*dy[p]));
	}
//	printf("QWQ :: %lld\n",ans);
	return ans;
}
inline void Solve()
{
	int X=read(),Y=read();char s[10];H=0;T=-1;
	memset(dis,0x3f,sizeof(dis));
	scanf("%s",s);rep(0,7,i)if(s[i]=='1'){dis[que[++T]=i]=1;}
	while(H<=T)
	{
		int u=que[H++];
		rep(0,7,i)if(s[i]=='1')
		{
			if(idx.count({dx[u]+dx[i],dy[u]+dy[i]}))
			{
				int v=idx[{dx[u]+dx[i],dy[u]+dy[i]}];
				if(dis[v]>=INF)dis[que[++T]=v]=dis[u]+1;
			}
		}
	}
//	rep(0,11,i)printf("%lld ",dis[i]>=INF?-1ll:dis[i]);puts("");
	ll ans=work(X,Y);if(ans>=INF)puts("-1");else printf("%lld\n",ans);
}
signed main()
{
	rep(0,11,i)idx[{dx[i],dy[i]}]=i;
	int T=read();while(T--)Solve();
}
